import{_ as t}from"./chunks/copilot-token-variable.CUNz-i72.js";import{_ as o,o as a,c as r,a2 as i}from"./chunks/framework._O8Cueap.js";const k=JSON.parse('{"title":"Copilot Token Variable Setup","description":"","frontmatter":{},"headers":[],"relativePath":"guide/copilot-token-variable.md","filePath":"guide/copilot-token-variable.md"}'),n={name:"guide/copilot-token-variable.md"};function d(l,e,s,c,h,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="copilot-token-variable-setup" tabindex="-1">Copilot Token Variable Setup <a class="header-anchor" href="#copilot-token-variable-setup" aria-label="Permalink to &quot;Copilot Token Variable Setup&quot;">​</a></h1><p>Most OAO agents can use the platform default <code>DEFAULT_LLM_API_KEY</code> or <code>GITHUB_TOKEN</code>, but production workspaces often need a shared credential that operators can rotate without redeploying the API. Store that token on the Variables page, then select it on the agents that should use it.</p><p>This tutorial uses placeholder values only. Never paste a real token into documentation, issue comments, screenshots, or workflow prompts.</p><h2 id="when-to-use-this" tabindex="-1">When To Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When To Use This&quot;">​</a></h2><p>Use a workspace-scoped Copilot token credential when many agents should share the same model authentication. Use a user-scoped credential when each operator should bring their own token. Use an agent-scoped credential only when one agent needs isolated billing, permissions, or rotation.</p><h2 id="_1-create-the-credential-variable" tabindex="-1">1. Create The Credential Variable <a class="header-anchor" href="#_1-create-the-credential-variable" aria-label="Permalink to &quot;1. Create The Credential Variable&quot;">​</a></h2><p>Open <code>http://oao.local/default/variables</code>, then create a variable with these settings:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Scope</td><td><code>Workspace</code> for a shared token, or <code>User</code> for a personal token</td></tr><tr><td>Key</td><td><code>COPILOT_TOKEN</code></td></tr><tr><td>Type</td><td><code>credential</code></td></tr><tr><td>Credential sub-type</td><td><code>GitHub Token</code></td></tr><tr><td>Value</td><td>Your GitHub Copilot token or compatible model API key</td></tr><tr><td>Inject as environment variable</td><td>Off</td></tr><tr><td>Description</td><td><code>Default Copilot token for workspace agents</code></td></tr></tbody></table><p><img src="'+t+'" alt="Copilot token credential variable detail"></p><p>The variable detail page intentionally does not show the stored value after creation. To rotate the token, open the same variable, enter a new value, and save it.</p><h2 id="_2-assign-it-to-an-agent" tabindex="-1">2. Assign It To An Agent <a class="header-anchor" href="#_2-assign-it-to-an-agent" aria-label="Permalink to &quot;2. Assign It To An Agent&quot;">​</a></h2><p>Open the agent create or edit page and find <strong>GitHub Copilot Token / LLM API Key</strong>. Select <code>COPILOT_TOKEN (Workspace - GitHub Token)</code> or the equivalent user-scoped option.</p><p>Recommended agent setup:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Source</td><td>Database or Git repository</td></tr><tr><td>Model auth</td><td><code>COPILOT_TOKEN</code></td></tr><tr><td>Built-in tools</td><td>Keep only the tools this agent needs</td></tr><tr><td>Scope</td><td><code>Workspace</code> for shared automation agents</td></tr></tbody></table><p>The agent stores only the credential variable id. The encrypted token remains in the Variables store and is resolved at runtime.</p><h2 id="_3-use-it-everywhere-safely" tabindex="-1">3. Use It Everywhere Safely <a class="header-anchor" href="#_3-use-it-everywhere-safely" aria-label="Permalink to &quot;3. Use It Everywhere Safely&quot;">​</a></h2><p>Once the variable exists, every new workflow can reuse agents that already reference it. For integrations that need their own external credentials, create separate variables such as <code>JIRA_API_TOKEN</code>, <code>SLACK_WEBHOOK_URL</code>, or <code>GITHUB_TOKEN</code> instead of reusing the Copilot token.</p><p>Use this pattern for common setup:</p><table tabindex="0"><thead><tr><th>Credential</th><th>Scope</th><th>Consumer</th></tr></thead><tbody><tr><td><code>COPILOT_TOKEN</code></td><td>Workspace</td><td>Agent model authentication</td></tr><tr><td><code>GITHUB_TOKEN</code></td><td>Workspace or User</td><td>GitHub MCP, Git clone auth, GitHub REST calls</td></tr><tr><td><code>JIRA_API_TOKEN</code></td><td>Workspace</td><td>Jira polling triggers</td></tr><tr><td><code>SLACK_WEBHOOK_URL</code></td><td>Workspace</td><td>Notification workflows using <code>simple_http_request</code></td></tr></tbody></table><h2 id="_4-verify-the-setup" tabindex="-1">4. Verify The Setup <a class="header-anchor" href="#_4-verify-the-setup" aria-label="Permalink to &quot;4. Verify The Setup&quot;">​</a></h2><ol><li>Open the agent detail page.</li><li>Click <strong>Edit</strong>.</li><li>Confirm <strong>GitHub Copilot Token / LLM API Key</strong> shows <code>COPILOT_TOKEN</code>.</li><li>Start a conversation or manual workflow run with that agent.</li><li>If model authentication fails, rotate the variable value and retry without changing the agent or workflow.</li></ol><h2 id="rotation-checklist" tabindex="-1">Rotation Checklist <a class="header-anchor" href="#rotation-checklist" aria-label="Permalink to &quot;Rotation Checklist&quot;">​</a></h2><ol><li>Create the replacement token in GitHub or your model provider.</li><li>Open <code>COPILOT_TOKEN</code> on the Variables page.</li><li>Paste the replacement value into <strong>New Value</strong>.</li><li>Save the variable.</li><li>Run a small agent conversation or manual workflow to confirm the new token works.</li><li>Revoke the old token from the provider.</li></ol>',23)])])}const g=o(n,[["render",d]]);export{k as __pageData,g as default};
